{
  "summary": "This paper presents a systematic comparison of language model (LM) architectures and encoder-decoder (EncDec) models for machine translation across various scales, multilingual settings, and zero-shot scenarios. It finds that while EncDec models dominate supervised translation, PrefixLM—a full-visible masking LM variant—excels in zero-shot translation by reducing off-target errors, with architectural differences diminishing at large scales. The study also highlights computational efficiency challenges for LMs compared to EncDec models.",
  "strengths": [
    {
      "point": "Comprehensive empirical study comparing LM and EncDec architectures across scales and multilingual tasks",
      "evidence": "Experiments cover bilingual, multilingual, and zero-shot translation on multiple datasets including WMT and OPUS-100, with varying model depths and widths."
    },
    {
      "point": "Identification of architectural design choices beneficial for LM-based translation",
      "evidence": "Full-visible masking (PrefixLM) consistently outperforms causal masking; increasing depth improves translation quality more than width; source-side language modeling loss is ineffective."
    },
    {
      "point": "Insightful findings on cross-lingual transfer capabilities",
      "evidence": "PrefixLM models reduce off-target translations and outperform EncDec in zero-shot settings, while EncDec models dominate supervised multilingual translation."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to recent large-scale decoder-only or encoder-only LM approaches for translation",
      "evidence": "The paper lacks discussion or benchmarking against state-of-the-art LM-based translation methods beyond the architectures tested, weakening novelty claims."
    },
    {
      "point": "Limited theoretical or empirical justification for masking strategy choices",
      "evidence": "No detailed rationale or ablation isolating why full-visible masking (PrefixLM) outperforms causal masking beyond empirical results."
    },
    {
      "point": "Reproducibility concerns due to incomplete training and architectural details",
      "evidence": "Key hyperparameters, data preprocessing steps, and precise LM architecture configurations are not fully specified."
    },
    {
      "point": "Evaluation metrics are limited primarily to BLEU and perplexity",
      "evidence": "Lack of semantic adequacy, fluency, or human evaluation metrics limits understanding of qualitative translation differences, especially in zero-shot."
    },
    {
      "point": "Unclear if model sizes and training budgets are strictly matched across architectures",
      "evidence": "Without strict parity, claims about efficiency and performance convergence may be confounded by differences in capacity or training regimes."
    },
    {
      "point": "Presentation and clarity issues in explaining architectural variants and results",
      "evidence": "Layer-wise coordination vs. top-only source encodings are not clearly explained; some key results lack comprehensive tables or figures."
    }
  ],
  "questions": [
    {
      "question": "How does PrefixLM compare to recent state-of-the-art large-scale decoder-only or encoder-only LM translation models?",
      "motivation": "Clarifying this would strengthen the novelty and practical relevance of the proposed approach."
    },
    {
      "question": "What are the underlying reasons that full-visible masking improves translation quality over causal masking?",
      "motivation": "A principled understanding could guide future architectural design beyond empirical observations."
    },
    {
      "question": "Can computational efficiency of LM architectures be improved to close the gap with EncDec models?",
      "motivation": "Addressing this would impact the feasibility of deploying LM-based translation models at scale."
    },
    {
      "question": "How well do the findings generalize to low-resource languages, domain-specific tasks, or other cross-lingual NLP tasks?",
      "motivation": "Understanding generalizability is important for broader applicability of the results."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
